    ```java
public int minMoves(int[] nums) {
    int min_element = nums[0];
    for (int num : nums) {
        min_element = Math.min(min_element, num);
    }
    int moves = 0;
    for (int num : nums) {
        moves += (num - min_element);
    }
    return moves;
}
```


